import { isUndefined } from 'lodash-es';
import type {
  Dispatch,
  MutableRefObject,
  SetStateAction,
  WheelEvent,
} from 'react';

import type {
  PointerEventModifiers,
  PointerEventPosition,
  RelativeAbsolutePosition,
} from '../../../../types/pointer-events.js';
import type { InteractionMode, InteractionTriggers } from '../../types.js';

export const exploreMouseHover = ({
  event,
  pinned,
  selectionArea,
  lastMousePositionRef,
  setCursorMode,
  onHover,
}: {
  event: PointerEventPosition & PointerEventModifiers;
  pinned: boolean;
  setCursorMode: Dispatch<SetStateAction<InteractionMode | 'zoomOut'>>;
  lastMousePositionRef: MutableRefObject<RelativeAbsolutePosition | undefined>;
  selectionArea?: [RelativeAbsolutePosition, RelativeAbsolutePosition];
  onHover?: (event: {
    triggeredBy: InteractionTriggers;
    position: RelativeAbsolutePosition;
  }) => void;
}) => {
  const canExplore = !pinned && isUndefined(selectionArea);

  const { position } = event;

  if (canExplore) {
    onHover?.({ triggeredBy: 'pointer', position });
  }
  lastMousePositionRef.current = position;

  setCursorMode('explore');
};

export const exploreMouseClickOrTap = ({
  event,
  selectionArea,
  onHover,
  onTogglePin,
  pinned,
  onSelectEnd,
  lastMousePositionRef,
}: {
  event: PointerEventPosition & PointerEventModifiers;
  pinned: boolean;
  lastMousePositionRef: MutableRefObject<RelativeAbsolutePosition | undefined>;
  selectionArea?: [RelativeAbsolutePosition, RelativeAbsolutePosition];
  onHover?: (event: {
    triggeredBy: InteractionTriggers;
    position: RelativeAbsolutePosition;
  }) => void;
  onTogglePin?: (event: {
    triggeredBy: InteractionTriggers;
    position: RelativeAbsolutePosition;
    pin: boolean;
  }) => void;

  onSelectEnd?: (
    event:
      | {
          triggeredBy: InteractionTriggers;
          start: RelativeAbsolutePosition;
          end: RelativeAbsolutePosition;
        }
      | { cancelled: true },
  ) => void;
}) => {
  const { position } = event;
  if (isUndefined(selectionArea)) {
    onHover?.({
      triggeredBy: 'pointer',
      position,
    });

    onTogglePin?.({
      triggeredBy: 'pointer',
      pin: !pinned,
      position,
    });
  } else {
    onSelectEnd?.({ cancelled: true });

    onHover?.({
      triggeredBy: 'pointer',
      position,
    });
  }
  lastMousePositionRef.current = position;
};

export const exploreMouseWheel = ({
  event,
  onPanChange,
}: {
  event: WheelEvent;
  onPanChange?: (event: {
    triggeredBy: InteractionTriggers;
    delta: number;
  }) => void;
}) => {
  const isTemporaryPanMode = (event: WheelEvent | KeyboardEvent) =>
    event.altKey;
  if (isTemporaryPanMode(event)) {
    const horizontal = event.deltaX && event.deltaX !== 0;
    if (horizontal) {
      onPanChange?.({ triggeredBy: 'pointer', delta: event.deltaX });
    }
  }
};
